# Generated by openai (gpt-5.4-mini)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '20'))
    }

    parameters {
        string(name: 'ARTIFACT_URL', defaultValue: '', description: 'Direct URL to the build artifact (S3 presigned URL, Artifactory URL, HTTP/HTTPS URL, etc.)')
        string(name: 'ARTIFACT_NAME', defaultValue: 'artifact.zip', description: 'Local filename to save the downloaded artifact as')
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/myapp/releases', description: 'Target directory on production servers')
        string(name: 'SERVERS', defaultValue: 'prod1.example.com,prod2.example.com', description: 'Comma-separated list of production servers')
        string(name: 'REMOTE_USER', defaultValue: 'deploy', description: 'SSH user for deployment')
        booleanParam(name: 'CLEAN_DEPLOY_PATH', defaultValue: false, description: 'Remove existing contents in deploy path before deploying')
        booleanParam(name: 'RESTART_SERVICE', defaultValue: true, description: 'Restart application service after deployment')
        string(name: 'SERVICE_NAME', defaultValue: 'myapp', description: 'Systemd service name to restart')
    }

    environment {
        DOWNLOAD_DIR = "${WORKSPACE}/download"
        DEPLOY_DIR = "${WORKSPACE}/deploy"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.ARTIFACT_URL?.trim()) {
                        error('ARTIFACT_URL is required')
                    }
                    if (!params.SERVERS?.trim()) {
                        error('SERVERS is required')
                    }
                    if (!params.DEPLOY_PATH?.trim()) {
                        error('DEPLOY_PATH is required')
                    }
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -e
                    rm -rf "${DOWNLOAD_DIR}" "${DEPLOY_DIR}"
                    mkdir -p "${DOWNLOAD_DIR}" "${DEPLOY_DIR}"
                '''
            }
        }

        stage('Download Artifact') {
            steps {
                sh '''
                    set -e
                    cd "${DOWNLOAD_DIR}"
                    echo "Downloading artifact from: ${ARTIFACT_URL}"
                    curl -fL --retry 3 --retry-delay 2 --connect-timeout 15 -o "${ARTIFACT_NAME}" "${ARTIFACT_URL}"
                    ls -lh "${ARTIFACT_NAME}"
                '''
            }
        }

        stage('Inspect Artifact') {
            steps {
                script {
                    def artifactPath = "${env.DOWNLOAD_DIR}/${params.ARTIFACT_NAME}"
                    if (!fileExists(artifactPath)) {
                        error("Downloaded artifact not found: ${artifactPath}")
                    }
                }
                sh '''
                    set -e
                    cd "${DOWNLOAD_DIR}"
                    file "${ARTIFACT_NAME}" || true
                '''
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = params.SERVERS.split(',').collect { it.trim() }.findAll { it }
                    if (servers.isEmpty()) {
                        error('No valid servers provided in SERVERS')
                    }

                    for (server in servers) {
                        echo "Deploying to ${server}"
                        sh """
                            set -e
                            ssh -o StrictHostKeyChecking=no ${params.REMOTE_USER}@${server} 'mkdir -p ${params.DEPLOY_PATH}'
                            scp -o StrictHostKeyChecking=no "${DOWNLOAD_DIR}/${params.ARTIFACT_NAME}" ${params.REMOTE_USER}@${server}:"${params.DEPLOY_PATH}/"
                        """

                        if (params.CLEAN_DEPLOY_PATH) {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no ${params.REMOTE_USER}@${server} '
                                    set -e
                                    cd "${params.DEPLOY_PATH}"
                                    find . -mindepth 1 -maxdepth 1 -exec rm -rf {} +
                                '
                            """
                        }

                        sh """
                            set -e
                            ssh -o StrictHostKeyChecking=no ${params.REMOTE_USER}@${server} '
                                set -e
                                cd "${params.DEPLOY_PATH}"
                                ARTIFACT_FILE="${params.ARTIFACT_NAME}"
                                case "$ARTIFACT_FILE" in
                                    *.zip)
                                        unzip -o "$ARTIFACT_FILE"
                                        ;;
                                    *.tar.gz|*.tgz)
                                        tar -xzf "$ARTIFACT_FILE"
                                        ;;
                                    *.tar)
                                        tar -xf "$ARTIFACT_FILE"
                                        ;;
                                    *)
                                        echo "Unsupported artifact type: $ARTIFACT_FILE"
                                        exit 1
                                        ;;
                                esac
                            '
                        """

                        if (params.RESTART_SERVICE) {
                            sh """
                                set -e
                                ssh -o StrictHostKeyChecking=no ${params.REMOTE_USER}@${server} '
                                    set -e
                                    sudo systemctl restart ${params.SERVICE_NAME}
                                    sudo systemctl status ${params.SERVICE_NAME} --no-pager -l || true
                                '
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        success {
            echo 'Deployment completed successfully'
        }
        failure {
            echo 'Deployment failed'
        }
        always {
            cleanWs(deleteDirs: true, disableDeferredWipeout: true)
        }
    }
}